#include<iostream>#include<vector>#include<climits>#define ll long longusing namespace std;void solve (){    ll p,q;        cin>>p>>q;        ll s= p + 2*q;        for(ll n=1;n<=20000;n++){            ll num= s - n;            ll dem= 2 * n + 1;            if(num>0 &&  num%dem==0){                ll m= num/dem;                 ll h= (n + 1)*m;                ll v= (m+ 1)*n;                if(abs(h-v)<= p){                    cout<<n<<" "<<m<<"\n";                    return ;                }            }        }        cout<<-1<<"\n";} int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        solve();    }}